1	import { db } from "@/lib/db";
2	
3	/**
4	 * Read/write surface for the principle distillation feature.
5	 *
6	 * The Codex stores `Principle` rows produced by the noosphere
7	 * distillation pipeline (see noosphere/distillation/principle_distillation.py).
8	 * Each row carries:
9	 *
10	 *   - text                  → single-sentence claim the firm is willing to defend
11	 *   - domains               → JSON string[] of domain tags (public-visible
12	 *                              principles must declare ≥1 domain)
13	 *   - clusterConclusionIds  → JSON string[] of conclusions in the embedding-
14	 *                              space cluster that produced the principle
15	 *   - citedConclusionIds    → JSON string[] of conclusions the LLM explicitly
16	 *                              quoted when drafting
17	 *   - convictionScore       → conservative score in [0, 1]; convergence-across-
18	 *                              domains weighted, not single-conclusion centrality
19	 *   - status                → draft | accepted | rejected | merged | needs_rereview
20	 *   - publicVisible         → founder-flipped flag; the public methodology
21	 *                              surface filters on this column AND on a
22	 *                              non-empty domain list AND on status=accepted
23	 *
24	 * The triage UI (queue + detail page) reads from here; the public
25	 * `/methodology/principles` page reads `listPublicPrinciples`.
26	 */
27	
28	export type PrincipleStatus =
29	  | "draft"
30	  | "accepted"
31	  | "rejected"
32	  | "merged"
33	  | "needs_rereview";
34	
35	export type PrincipleRow = {
36	  id: string;
37	  text: string;
38	  domains: string[];
39	  clusterConclusionIds: string[];
40	  citedConclusionIds: string[];
41	  status: PrincipleStatus;
42	  triageReason: string;
43	  mergedIntoId: string | null;
44	  convictionScore: number;
45	  domainBreadth: number;
46	  clusterCentroidSimilarity: number;
47	  publicVisible: boolean;
48	  driftReason: string | null;
49	  reviewedAt: Date | null;
50	  publishedAt: Date | null;
51	  createdAt: Date;
52	  updatedAt: Date;
53	};
54	
55	export type PublicPrincipleRow = PrincipleRow & {
56	  underlyingConclusions: Array<{
57	    id: string;
58	    text: string;
59	    confidenceTier: string;
60	  }>;
61	};
62	
63	function safeParseJsonStringArray(value: string): string[] {
64	  try {
65	    const parsed = JSON.parse(value);
66	    if (!Array.isArray(parsed)) return [];
67	    return parsed.filter((x): x is string => typeof x === "string");
68	  } catch {
69	    return [];
70	  }
71	}
72	
73	function rowFromPrisma(p: {
74	  id: string;
75	  text: string;
76	  domainsJson: string;
77	  clusterConclusionIds: string;
78	  citedConclusionIds: string;
79	  status: string;
80	  triageReason: string;
81	  mergedIntoId: string | null;
82	  convictionScore: number;
83	  domainBreadth: number;
84	  clusterCentroidSimilarity: number;
85	  publicVisible: boolean;
86	  driftReason: string | null;
87	  reviewedAt: Date | null;
88	  publishedAt: Date | null;
89	  createdAt: Date;
90	  updatedAt: Date;
91	}): PrincipleRow {
92	  return {
93	    id: p.id,
94	    text: p.text,
95	    domains: safeParseJsonStringArray(p.domainsJson),
96	    clusterConclusionIds: safeParseJsonStringArray(p.clusterConclusionIds),
97	    citedConclusionIds: safeParseJsonStringArray(p.citedConclusionIds),
98	    status: (p.status as PrincipleStatus) ?? "draft",
99	    triageReason: p.triageReason ?? "",
100	    mergedIntoId: p.mergedIntoId,
101	    convictionScore: p.convictionScore,
102	    domainBreadth: p.domainBreadth,
103	    clusterCentroidSimilarity: p.clusterCentroidSimilarity,
104	    publicVisible: p.publicVisible,
105	    driftReason: p.driftReason,
106	    reviewedAt: p.reviewedAt,
