function ClaimSummary({
  claim,
  tier,
  tierColor,
  confidence,
  topicHint,
  attribution,
  rationale,
  createdAt,
  updatedAt,
  sources,
}: {
  claim: string;
  tier: string;
  tierColor: string;
  confidence: number;
  topicHint: string;
  attribution: string;
  rationale: string;
  createdAt: string;
  updatedAt: string;
  sources: { uploadId: string; title: string; sourceType: string }[];
}) {
  const pct = Math.max(0, Math.min(1, confidence)) * 100;
  const showUpdated = updatedAt && updatedAt !== createdAt;
  return (
    <header style={{ marginBottom: "1rem" }}>
      <blockquote
        style={{
          margin: 0,
          padding: "0.85rem 1.15rem",
          borderLeft: `3px solid ${tierColor}`,
          background: "var(--stone-light)",
          fontSize: "1.1rem",
          lineHeight: 1.55,
          color: "var(--parchment)",
        }}
      >
        {claim}
      </blockquote>

      <dl
        style={{
          display: "flex",
          flexWrap: "wrap",
          gap: "0.4rem 1rem",
          margin: "0.75rem 0 0",
          padding: 0,
          fontSize: "0.75rem",
          color: "var(--parchment-dim)",
          alignItems: "baseline",
        }}
      >
        <SummaryPair label="Tier">
          <span
            style={{
              color: tierColor,
              textTransform: "uppercase",
              letterSpacing: "0.1em",
              fontFamily: "'Cinzel', serif",
              fontSize: "0.7rem",
            }}
          >
            {tier}
          </span>
        </SummaryPair>
        <SummaryPair label="Confidence">
          <span style={{ color: "var(--parchment)" }}>{pct.toFixed(0)}%</span>
        </SummaryPair>
        {topicHint ? (
          <SummaryPair label="Topic">
            <span style={{ color: "var(--parchment)" }}>{topicHint}</span>
          </SummaryPair>
        ) : null}
        {attribution ? (
          <SummaryPair label="Attributed to">
            <span style={{ color: "var(--parchment)" }}>{attribution}</span>
          </SummaryPair>
        ) : null}
        {createdAt ? (
          <SummaryPair label={showUpdated ? "Created" : "Recorded"}>
            <time dateTime={createdAt} style={{ color: "var(--parchment)" }}>
              {createdAt}
            </time>
          </SummaryPair>
        ) : null}
        {showUpdated ? (
          <SummaryPair label="Updated">
            <time dateTime={updatedAt} style={{ color: "var(--parchment)" }}>
              {updatedAt}
            </time>
          </SummaryPair>
        ) : null}
      </dl>

      {rationale ? (
        <p
          style={{
            margin: "0.65rem 0 0",
            fontSize: "0.9rem",
            color: "var(--parchment)",
            lineHeight: 1.55,
          }}
        >
          <span
            className="mono"
            style={{
              color: "var(--parchment-dim)",
              fontSize: "0.6rem",
              letterSpacing: "0.18em",
              textTransform: "uppercase",
              marginRight: "0.45rem",
            }}
          >
            Rationale
          </span>
          {rationale}
        </p>
      ) : null}

      {sources.length > 0 ? (
        <div
          style={{
            margin: "0.65rem 0 0",
            display: "flex",
            flexWrap: "wrap",
            gap: "0.4rem",
            alignItems: "center",
          }}
        >
          <span
            className="mono"
            style={{
              color: "var(--parchment-dim)",
              fontSize: "0.6rem",
              letterSpacing: "0.18em",
              textTransform: "uppercase",
            }}
          >
            Source
          </span>
          {sources.map((s) => (
            <Link
              key={s.uploadId}
              href="/knowledge?tab=library"
              style={{
                padding: "0.15rem 0.55rem",
                border: "1px solid var(--border)",
                borderRadius: 2,
                color: "var(--parchment)",
                textDecoration: "none",
                fontSize: "0.75rem",
