      {sourceUploads.length > 0 ? (
        <div style={{ borderTop: "1px solid var(--border)", paddingTop: "0.85rem" }}>
          <h3
            className="mono"
            style={{
              color: "var(--parchment-dim)",
              fontSize: "0.58rem",
              letterSpacing: "0.2em",
              margin: "0 0 0.55rem",
              textTransform: "uppercase",
