          <div style={{ display: "grid", gap: "0.5rem" }}>
            {sourceUploads.map((source) => (
              <div
                key={source.uploadId}
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  gap: "0.8rem",
                  flexWrap: "wrap",
