              >
                <span style={{ color: "var(--parchment)", fontSize: "0.82rem" }}>
                  {source.title}
                  <span style={{ color: "var(--parchment-dim)", marginLeft: "0.45rem" }}>
                    {source.sourceType}
                  </span>
