        />
      ) : reviews.length > 0 ? (
        <div style={{ borderTop: "1px solid var(--border)", paddingTop: "0.85rem" }}>
          {reviews.map((review) => (
            <p key={review.id} style={{ color: "var(--parchment-dim)", fontSize: "0.78rem", margin: "0.25rem 0" }}>
              {review.status} · updated {review.updatedAt.slice(0, 10)}
            </p>
          ))}
        </div>
      ) : null}
    </div>
  );
}

function OverviewTab({
  supportIds,
  evidenceIds,
  dissentIds,
  idTextMap,
  sources,
}: {
  supportIds: string[];
  evidenceIds: string[];
  dissentIds: string[];
  idTextMap: Record<string, string>;
  sources: { uploadId: string; title: string; sourceType: string }[];
}) {
  const lists: Array<{ label: string; ids: string[] }> = [
    { label: "Supporting principles", ids: supportIds },
    { label: "Evidence chain claims", ids: evidenceIds },
    { label: "Dissenting claims", ids: dissentIds },
  ];
  const nonEmpty = lists.filter((l) => l.ids.length > 0);
  const empty = lists.filter((l) => l.ids.length === 0);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
      {nonEmpty.map((l) => (
        <ExpandableIdList
          key={l.label}
          label={l.label}
          ids={l.ids}
          idTextMap={idTextMap}
        />
      ))}

      {empty.length > 0 ? (
        <p
          className="mono"
          style={{
            margin: 0,
            color: "var(--parchment-dim)",
            fontSize: "0.7rem",
            letterSpacing: "0.12em",
          }}
        >
          {empty
            .map((l) => `${l.label.toLowerCase()}: none`)
            .join(" · ")}
        </p>
      ) : null}

      {sources.length > 0 && (
        <div>
          <div
            className="mono"
            style={{
              fontSize: "0.6rem",
              letterSpacing: "0.18em",
              textTransform: "uppercase",
              color: "var(--parchment-dim)",
              marginBottom: "0.4rem",
            }}
          >
            Source documents
          </div>
          {sources.map((s) => (
            <Link
              key={s.uploadId}
              href="/knowledge?tab=library"
              style={{
                display: "block",
                padding: "0.4rem 0.75rem",
                borderLeft: "2px solid var(--gold-dim)",
                marginBottom: "0.25rem",
                color: "var(--parchment)",
                textDecoration: "none",
                fontSize: "0.85rem",
              }}
            >
              {s.title}
              <span
                style={{
                  fontSize: "0.65rem",
                  color: "var(--parchment-dim)",
                  marginLeft: "0.5rem",
                }}
              >
                {s.sourceType}
              </span>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}

function ExpandableIdList({
  label,
  ids,
  idTextMap,
}: {
  label: string;
  ids: string[];
  idTextMap: Record<string, string>;
}) {
  return (
    <details
      style={{
        padding: "0.65rem 0.85rem",
        border: "1px solid var(--border)",
        borderRadius: 2,
      }}
    >
      <summary
        style={{
          cursor: "pointer",
          display: "flex",
          justifyContent: "space-between",
          alignItems: "baseline",
        }}
      >
        <span
          className="mono"
          style={{
            fontSize: "0.6rem",
            letterSpacing: "0.18em",
            textTransform: "uppercase",
            color: "var(--parchment-dim)",
          }}
        >
          {label}
        </span>
        <span
          style={{
            fontSize: "1rem",
            color: "var(--gold)",
            fontFamily: "'Cinzel', serif",
          }}
        >
          {ids.length}
        </span>
      </summary>
      <div style={{ marginTop: "0.5rem", display: "flex", flexDirection: "column", gap: "0.4rem" }}>
        {ids.map((id) => {
          const text = idTextMap[id];
          return (
            <div
              key={id}
              style={{
                padding: "0.35rem 0.5rem",
                borderLeft: "2px solid var(--border)",
              }}
            >
              {text ? (
                <p style={{ margin: 0, fontSize: "0.85rem", color: "var(--parchment)" }}>
                  {text}
                </p>
              ) : (
                <p
                  style={{
                    margin: 0,
                    fontSize: "0.75rem",
                    color: "var(--parchment-dim)",
                    fontStyle: "italic",
                  }}
                >
                  {id.slice(0, 12)}… — text unavailable (may require Noosphere
                  connection)
                </p>
              )}
            </div>
          );
        })}
      </div>
    </details>
  );
}

