57	function excerpt(text: string | null | undefined, max = 360): string {
58	  const cleaned = (text || "").replace(/\s+/g, " ").trim();
59	  if (cleaned.length <= max) return cleaned;
60	  return `${cleaned.slice(0, max - 3).trimEnd()}...`;
61	}
