63	function tokenize(text: string): Set<string> {
64	  return new Set(
65	    text
66	      .toLowerCase()
67	      .replace(/[^a-z0-9\s]/g, " ")
68	      .split(/\s+/)
69	      .filter((token) => token.length >= 3 && !STOPWORDS.has(token)),
70	  );
71	}
72	
73	function overlapScore(left: string, right: string): number {
74	  const a = tokenize(left);
75	  const b = tokenize(right);
76	  if (a.size === 0 || b.size === 0) return 0;
77	  let hits = 0;
78	  for (const token of b) {
79	    if (a.has(token)) hits++;
80	  }
81	  return hits / Math.sqrt(a.size);
82	}
83	
84	function cosine(left: number[], right: number[]): number | null {
85	  if (left.length !== right.length || left.length === 0) return null;
86	  let dot = 0;
87	  let leftNorm = 0;
88	  let rightNorm = 0;
89	  for (let index = 0; index < left.length; index++) {
90	    dot += left[index]! * right[index]!;
91	    leftNorm += left[index]! * left[index]!;
92	    rightNorm += right[index]! * right[index]!;
93	  }
94	  if (leftNorm === 0 || rightNorm === 0) return null;
95	  return dot / (Math.sqrt(leftNorm) * Math.sqrt(rightNorm));
96	}
