114	async function semanticRelatedConclusions(organizationId: string, uploadId: string) {
115	  try {
116	    const modelName = await activeEmbeddingModelName();
117	    const [chunkRows, conclusionRows] = await Promise.all([
118	      db.$queryRaw<SemanticChunkRow[]>`
119	        SELECT uc.id, e.vector, e.dimension
120	        FROM "UploadChunk" uc
121	        INNER JOIN embedding e ON e.ref_claim_id = uc.id
122	        WHERE uc."uploadId" = ${uploadId}
123	          AND e.model_name = ${modelName}
124	      `,
125	      db.$queryRaw<SemanticConclusionRow[]>`
126	        SELECT c.id,
127	               c.text,
128	               c."confidenceTier",
129	               c."topicHint",
130	               c.rationale,
131	               e.vector,
132	               e.dimension
133	        FROM "Conclusion" c
134	        INNER JOIN embedding e ON e.ref_claim_id = c.id
135	        WHERE c."organizationId" = ${organizationId}
136	          AND e.model_name = ${modelName}
137	        ORDER BY c."createdAt" DESC
138	        LIMIT 200
139	      `,
140	    ]);
141	    const chunkVectors = chunkRows
142	      .map((row) => decodeFloat32Vector(row.vector, row.dimension))
143	      .filter((vector) => vector.length > 0);
144	    if (chunkVectors.length === 0 || conclusionRows.length === 0) return [];
145	
146	    return conclusionRows
147	      .map((row) => {
148	        const conclusionVector = decodeFloat32Vector(row.vector, row.dimension);
149	        const score = Math.max(
150	          0,
151	          ...chunkVectors
152	            .map((chunkVector) => cosine(chunkVector, conclusionVector))
153	            .filter((value): value is number => value !== null),
154	        );
155	        return { ...row, score };
156	      })
157	      .filter((row) => row.score > 0.18)
158	      .sort((a, b) => b.score - a.score || a.id.localeCompare(b.id))
159	      .slice(0, 5);
160	  } catch {
161	    return [];
162	  }
163	}
