165	async function relatedConclusions(organizationId: string, transcriptText: string, uploadId: string) {
166	  const semantic = await semanticRelatedConclusions(organizationId, uploadId);
167	  if (semantic.length > 0) return semantic;
168	
169	  const rows = await db.conclusion.findMany({
