389	          {hasTranscript ? (
390	            <TranscriptReader chunks={displayChunks} uploadId={upload.id} />
391	          ) : (
392	            <section className="portal-card transcript-empty">
393	              This upload has no persisted transcript chunks yet. Re-run ingestion to create stable line anchors.
394	            </section>
395	          )}
396	        </article>
397	
398	        <aside className="transcript-side-rail" aria-label="Transcript navigation">
399	          <section className="portal-card transcript-blurb-card" aria-labelledby="transcript-blurb-title">
400	            <h2 className="mono" id="transcript-blurb-title">
401	              Blurb
402	            </h2>
403	            <p>{blurb || "No blurb has been generated for this upload yet."}</p>
404	          </section>
405	          {headings.length > 0 ? (
406	            <nav className="portal-card transcript-section-nav" aria-label="Transcript sections">
407	              <h2 className="mono">Sections</h2>
408	              <ul>
409	                {headings.map((heading) => (
410	                  <li key={heading.anchor}>
411	                    <a
412	                      href={`/transcripts/${encodeURIComponent(upload.id)}?anchor=${encodeURIComponent(heading.anchor)}`}
413	                    >
414	                      {heading.label}
415	                    </a>
416	                  </li>
417	                ))}
418	              </ul>
419	            </nav>
420	          ) : null}
421	          <section className="portal-card transcript-related-rail" aria-label="What the firm thinks about this">
422	            <RelatedPanel related={related} />
423	          </section>
424	        </aside>
425	      </div>
426	
427	      <section className="transcript-analysis" aria-label="Transcript analysis">
428	        <p className="mono transcript-analysis-kicker">Analysis (secondary)</p>
429	        {!hasSpeakerLabels && conversationLike ? (
430	          <p className="transcript-analysis-note">
431	            No speaker labels were detected on this transcript. Conversation geometry is not used as the source identity here.
432	          </p>
433	        ) : null}
434	        <div className="transcript-insight-grid">
435	          {showConversationGeometry ? (
436	            <ConversationGeometryPanel
437	              geometry={geometry}
438	              uploadId={upload.id}
439	              yearStats={yearStats}
440	            />
441	          ) : (
442	            <SourceStructurePanel chunks={displayChunks} />
443	          )}
444	          <MethodologyProfilesPanel profiles={methodologyProfiles} />
445	        </div>
446	      </section>
447	    </main>
448	  );
449	}
450	
451	function RelatedPanel({
452	  related,
453	}: {
454	  related: Awaited<ReturnType<typeof relatedConclusions>>;
455	}) {
456	  return (
457	    <div className="transcript-related-panel">
458	      <h2 className="mono">What the firm thinks about this</h2>
459	      {related.length > 0 ? (
460	        <div className="transcript-related-list">
461	          {related.map((item) => (
462	            <Link className="transcript-related-card" href={`/conclusions/${item.id}`} key={item.id}>
463	              <span className="mono">[C:{item.id.slice(0, 8)}] / {item.confidenceTier}</span>
464	              <strong>{item.text}</strong>
465	              {item.topicHint ? <em>{item.topicHint}</em> : null}
466	            </Link>
467	          ))}
468	        </div>
469	      ) : (
470	        <p className="transcript-related-empty">
471	          No overlapping firm conclusions were found. This panel falls back to keyword overlap when embeddings are unavailable.
472	        </p>
473	      )}
474	    </div>
475	  );
476	}
