1	import Link from "next/link";
2	import { redirect } from "next/navigation";
3	
4	import { getFounder } from "@/lib/auth";
5	import { db } from "@/lib/db";
6	import { normalizeDecisionTrace } from "@/lib/forecastPortfolioData";
7	import { getForecast, getPortfolioSummary, listForecasts } from "@/lib/forecastsApi";
8	import { getOperatorSetupStatus, listOperatorLiveBets } from "@/lib/forecastsOperatorApi";
9	import type {
10	  DecisionTrace,
11	  OperatorBet,
12	  OperatorKillSwitchState,
13	  OperatorSetupStatus,
14	  PortfolioSummary,
15	  PublicForecast,
16	} from "@/lib/forecastsTypes";
17	import { canWrite } from "@/lib/roles";
18	
19	import KillSwitchPanel from "./KillSwitchPanel";
20	import LiveBetLedger from "./LiveBetLedger";
21	import PendingAuthorizations, { type AuthorizationRow } from "./PendingAuthorizations";
22	import PendingConfirmations, { type ConfirmGateContext } from "./PendingConfirmations";
23	
24	export const dynamic = "force-dynamic";
25	
26	const DEFAULT_MAX_STAKE_USD = 0;
27	const DEFAULT_KELLY_FRACTION = 0.25;
28	
29	function envFlag(name: string): boolean {
30	  return process.env[name]?.trim().toLowerCase() === "true";
31	}
32	
33	function envNumber(name: string): number | null {
34	  const raw = process.env[name]?.trim();
35	  if (!raw) return null;
36	  const parsed = Number(raw);
37	  return Number.isFinite(parsed) ? parsed : null;
38	}
39	
40	function numericField(row: object | null | undefined, ...keys: string[]): number | null {
41	  if (!row) return null;
42	  for (const key of keys) {
43	    const value = (row as Record<string, unknown>)[key];
44	    if (typeof value === "number" && Number.isFinite(value)) return value;
45	  }
46	  return null;
47	}
48	
49	function marketPrice(prediction: PublicForecast): number | null {
50	  const price = prediction.market?.current_yes_price;
51	  return typeof price === "number" && Number.isFinite(price) ? price : null;
52	}
53	
54	function modelEdge(prediction: PublicForecast): number | null {
55	  const p = prediction.probability_yes;
56	  const price = marketPrice(prediction);
57	  if (p === null || price === null || !Number.isFinite(p)) return null;
58	  return p - price;
59	}
60	
61	function kellyStakeUsd({
62	  bankrollUsd,
63	  marketPrice,
64	  maxStakeUsd,
65	  modelProbability,
66	}: {
67	  bankrollUsd: number;
68	  marketPrice: number | null;
69	  maxStakeUsd: number;
70	  modelProbability: number | null;
71	}): number {
72	  if (
73	    marketPrice === null ||
74	    modelProbability === null ||
75	    !Number.isFinite(marketPrice) ||
76	    !Number.isFinite(modelProbability) ||
77	    marketPrice <= 0 ||
78	    marketPrice >= 1 ||
79	    bankrollUsd <= 0 ||
80	    maxStakeUsd <= 0
81	  ) {
82	    return 0;
83	  }
84	  const rawFraction = (modelProbability - marketPrice) / (1 - marketPrice);
85	  const fraction = Math.min(1, Math.max(0, rawFraction));
86	  return Math.min(maxStakeUsd, fraction * DEFAULT_KELLY_FRACTION * bankrollUsd);
87	}
88	
89	async function fetchLiveBets(limit = 200): Promise<OperatorBet[]> {
90	  const out: OperatorBet[] = [];
91	  let offset = 0;
92	  while (out.length < limit) {
93	    const response = await listOperatorLiveBets({ limit: Math.min(100, limit - out.length), offset });
94	    out.push(...response.items);
95	    if (response.next_offset === null || response.items.length === 0) break;
96	    offset = response.next_offset;
97	  }
98	  return out;
99	}
100	
101	async function decisionTracesByPrediction(predictionIds: string[]): Promise<Record<string, DecisionTrace>> {
102	  const unique = Array.from(new Set(predictionIds.filter(Boolean)));
103	  if (unique.length === 0) return {};
104	  try {
105	    const rows = await db.forecastTrace.findMany({
106	      select: { modelOutput: true, predictionId: true },
107	      where: { predictionId: { in: unique } },
108	    });
109	    const out: Record<string, DecisionTrace> = {};
110	    for (const row of rows) {
111	      const trace = normalizeDecisionTrace(row.modelOutput);
112	      if (trace) out[row.predictionId] = trace;
113	    }
114	    return out;
115	  } catch (error) {
116	    console.error("operator_decision_trace_fetch_failed", error);
117	    return {};
118	  }
119	}
120	
121	async function predictionsForBets(seed: PublicForecast[], bets: OperatorBet[]): Promise<Record<string, PublicForecast>> {
122	  const byId: Record<string, PublicForecast> = {};
123	  for (const prediction of seed) {
124	    byId[prediction.id] = prediction;
125	  }
126	  const missing = Array.from(new Set(bets.map((bet) => bet.prediction_id).filter((id) => !byId[id])));
127	  await Promise.all(
128	    missing.map(async (id) => {
129	      try {
130	        byId[id] = await getForecast(id);
131	      } catch (error) {
132	        console.error("operator_forecast_fetch_failed", id, error);
133	      }
134	    }),
135	  );
136	  return byId;
137	}
138	
139	function authorizationRows(
140	  forecasts: PublicForecast[],
141	  options: {
142	    bankrollUsd: number;
143	    maxStakeUsd: number;
144	  },
145	): AuthorizationRow[] {
146	  return forecasts
147	    .filter((prediction) => prediction.status === "PUBLISHED")
148	    .filter((prediction) => prediction.live_authorized_at === null)
149	    .map((prediction) => {
150	      const price = marketPrice(prediction);
151	      return {
152	        edge: modelEdge(prediction),
153	        kellyStakeUsd: kellyStakeUsd({
154	          bankrollUsd: options.bankrollUsd,
155	          marketPrice: price,
156	          maxStakeUsd: options.maxStakeUsd,
157	          modelProbability: prediction.probability_yes,
158	        }),
159	        marketPrice: price,
160	        prediction,
161	      };
162	    });
163	}
164	
165	function configuredExchanges(): string[] {
166	  const exchanges: string[] = [];
167	  if (process.env.POLYMARKET_PRIVATE_KEY?.trim()) exchanges.push("POLYMARKET");
168	  const kalshiPrivateKey = process.env.KALSHI_API_PRIVATE_KEY?.trim() || process.env.KALSHI_PRIVATE_KEY_PEM?.trim();
169	  if (process.env.KALSHI_API_KEY_ID?.trim() && kalshiPrivateKey) exchanges.push("KALSHI");
170	  return exchanges;
171	}
172	
173	function killSwitchState(summary: PortfolioSummary): OperatorKillSwitchState {
174	  return {
175	    kill_switch_engaged: summary.kill_switch_engaged,
176	    kill_switch_reason: summary.kill_switch_reason,
177	    organization_id: summary.organization_id,
178	    updated_at: summary.updated_at,
179	  };
180	}
181	
182	export default async function ForecastsOperatorPage() {
183	  const founder = await getFounder();
184	  if (!founder) redirect("/login");
185	  if (!canWrite(founder.role)) redirect("/dashboard");
186	
187	  const liveTradingEnabled = envFlag("FORECASTS_LIVE_TRADING_ENABLED");
188	  const maxStakeUsd = envNumber("FORECASTS_MAX_STAKE_USD") ?? DEFAULT_MAX_STAKE_USD;
189	  const maxDailyLossUsd = envNumber("FORECASTS_MAX_DAILY_LOSS_USD");
190	
191	  const [forecastResult, betsResult, summaryResult, setupResult] = await Promise.allSettled([
192	    listForecasts({ limit: 100, status: "PUBLISHED" }),
193	    fetchLiveBets(200),
194	    getPortfolioSummary(),
195	    getOperatorSetupStatus(),
196	  ]);
197	
198	  const forecasts = forecastResult.status === "fulfilled" ? forecastResult.value.items : [];
199	  const liveBets = betsResult.status === "fulfilled" ? betsResult.value : [];
200	  const setupStatus: OperatorSetupStatus | null =
201	    setupResult.status === "fulfilled" ? setupResult.value : null;
202	  const summary =
203	    summaryResult.status === "fulfilled"
204	      ? summaryResult.value
