109	type JsonRecord = Record<string, unknown>;
110	
111	function csvEnv(name: string): string[] {
112	  return (process.env[name] ?? "")
113	    .split(",")
114	    .map((part) => part.trim())
115	    .filter(Boolean);
116	}
117	
118	function decimalNumber(value: unknown): number | null {
119	  if (value === null || value === undefined) return null;
120	  const parsed = Number(value);
121	  return Number.isFinite(parsed) ? parsed : null;
122	}
123	
124	function money(value: unknown): number {
125	  return decimalNumber(value) ?? 0;
126	}
127	
128	function jsonRecord(value: unknown): JsonRecord {
129	  return value && typeof value === "object" && !Array.isArray(value)
130	    ? (value as JsonRecord)
131	    : {};
132	}
133	
134	function jsonArray(value: unknown): unknown[] {
135	  return Array.isArray(value) ? value : [];
136	}
137	
138	export function normalizeTracePrinciples(value: unknown): TracePrinciple[] {
139	  return jsonArray(value)
140	    .map((item) => jsonRecord(item))
141	    .map((item) => ({
142	      conclusionId: String(item.conclusionId ?? item.conclusion_id ?? ""),
143	      snippet: String(item.snippet ?? ""),
144	      weight: decimalNumber(item.weight) ?? 0,
145	    }))
146	    .filter((item) => item.conclusionId.length > 0);
147	}
148	
149	export function normalizeGateResults(value: unknown): TraceGateResult[] {
150	  return jsonArray(value)
151	    .map((item) => jsonRecord(item))
152	    .map((item) => ({
153	      gateName: String(item.gateName ?? item.gate_name ?? ""),
154	      passed: Boolean(item.passed),
155	      reason: String(item.reason ?? item.detail ?? ""),
156	    }))
157	    .filter((item) => item.gateName.length > 0);
158	}
159	
160	const ALLOWED_ACTIONS: Set<DecisionAction> = new Set([
161	  "ABSTAIN",
162	  "WATCH",
163	  "PAPER_TRADE",
164	  "LIVE_CANDIDATE",
165	  "REDUCE",
166	  "EXIT",
167	  "HEDGE",
168	]);
169	
170	function coerceAction(value: unknown): DecisionAction {
171	  const raw = String(value ?? "").toUpperCase();
172	  return (ALLOWED_ACTIONS.has(raw as DecisionAction) ? raw : "ABSTAIN") as DecisionAction;
173	}
174	
175	function coerceSide(value: unknown): "YES" | "NO" | null {
176	  const raw = String(value ?? "").toUpperCase();
177	  if (raw === "YES" || raw === "NO") return raw;
178	  return null;
179	}
180	
181	function normalizeDecisionMetrics(value: unknown): DecisionMetric[] {
182	  return jsonArray(value)
183	    .map((item) => jsonRecord(item))
184	    .map((item) => {
185	      const range = Array.isArray(item.range) ? item.range : [0, 1];
186	      const rangeLow = decimalNumber(range[0]) ?? 0;
187	      const rangeHigh = decimalNumber(range[1]) ?? 1;
188	      return {
189	        detail: String(item.detail ?? ""),
190	        lowConfidence: Boolean(item.low_confidence ?? item.lowConfidence),
191	        method: String(item.method ?? ""),
192	        name: String(item.name ?? ""),
193	        rangeHigh,
194	        rangeLow,
195	        value: decimalNumber(item.value) ?? 0,
196	      };
197	    })
198	    .filter((m) => m.name.length > 0);
199	}
200	
201	function normalizeDecisionRules(value: unknown): DecisionRule[] {
202	  return jsonArray(value)
203	    .map((item) => jsonRecord(item))
204	    .map((item) => ({
205	      detail: String(item.detail ?? ""),
206	      fired: Boolean(item.fired),
207	      kind: String(item.kind ?? "threshold"),
208	      name: String(item.name ?? ""),
209	      passed: Boolean(item.passed),
210	    }))
211	    .filter((r) => r.name.length > 0);
212	}
213	
214	export function normalizeDecisionTrace(
215	  modelOutput: unknown,
216	  fallback?: { marketYesPrice: number | null; firmProbabilityYes: number | null },
217	): DecisionTrace | null {
218	  const root = jsonRecord(modelOutput);
219	  const inner = jsonRecord(root.decision_trace);
220	  if (Object.keys(inner).length === 0 && !root.decision_action && !root.side) return null;
221	
222	  const action = coerceAction(inner.action ?? root.decision_action ?? "ABSTAIN");
223	  const side = coerceSide(inner.side ?? root.side);
224	  const metrics = normalizeDecisionMetrics(inner.metrics);
225	  const rules = normalizeDecisionRules(inner.rules);
226	  const reasons = jsonArray(inner.reasons).map((r) => String(r));
227	  const edgeMetric = metrics.find((m) => m.name === "market_mispricing_edge");
228	  const firmProbabilityYes =
229	    fallback?.firmProbabilityYes ??
230	    (edgeMetric?.detail.match(/firm_p=([0-9.]+)/)?.[1]
231	      ? Number(edgeMetric.detail.match(/firm_p=([0-9.]+)/)?.[1])
232	      : null);
233	  const marketYesPrice =
234	    fallback?.marketYesPrice ??
235	    (edgeMetric?.detail.match(/market_p=([0-9.]+)/)?.[1]
236	      ? Number(edgeMetric.detail.match(/market_p=([0-9.]+)/)?.[1])
237	      : null);
238	  const edge = decimalNumber(root.edge) ?? (edgeMetric ? edgeMetric.value : null);
239	  return {
240	    action,
241	    confidence: decimalNumber(inner.confidence) ?? 0,
242	    edge,
243	    firmProbabilityYes,
244	    marketYesPrice,
245	    metrics,
246	    rationale: typeof root.rationale === "string" ? root.rationale : null,
247	    reasons,
248	    rules,
249	    side,
250	    stakeRecommendationUsd: decimalNumber(inner.stake_recommendation_usd),
251	    traceVersion: String(inner.trace_version ?? ""),
252	  };
253	}
254	
255	function liveTradingEnabled(): boolean {
256	  return process.env.FORECASTS_LIVE_TRADING_ENABLED?.trim().toLowerCase() === "true";
257	}
258	
259	function modeState(args: {
260	  killSwitchEngaged: boolean;
261	  killSwitchReason: string | null;
262	}): PortfolioModeState {
263	  if (!liveTradingEnabled()) {
264	    return { mode: "PAPER", liveTradingEnabled: false, failedGates: [] };
265	  }
266	
267	  const failedGates: TraceGateResult[] = [];
268	  const hasPolymarket = Boolean(process.env.POLYMARKET_PRIVATE_KEY?.trim());
269	  const hasKalshi = Boolean(
270	    process.env.KALSHI_API_KEY_ID?.trim() &&
271	      (process.env.KALSHI_API_PRIVATE_KEY?.trim() ||
272	        process.env.KALSHI_PRIVATE_KEY_PEM?.trim()),
273	  );
274	
275	  if (!hasPolymarket && !hasKalshi) {
276	    failedGates.push({
277	      gateName: "exchange_credentials_configured",
278	      passed: false,
279	      reason: "no live exchange credentials are configured",
280	    });
281	  }
282	
283	  if (args.killSwitchEngaged) {
284	    failedGates.push({
285	      gateName: "kill_switch_clear",
286	      passed: false,
287	      reason: args.killSwitchReason || "portfolio kill switch is engaged",
288	    });
289	  }
290	
291	  return {
292	    mode: failedGates.length > 0 ? "GATE-BLOCKED" : "LIVE",
293	    liveTradingEnabled: true,
294	    failedGates,
295	  };
296	}
297	
298	function marketUrl(market: {
299	  externalId: string;
300	  rawPayload: unknown;
301	  source: ForecastSource | string;
302	}): string | null {
303	  const raw = jsonRecord(market.rawPayload);
304	  for (const key of ["url", "market_url", "source_url"]) {
305	    const value = raw[key];
306	    if (typeof value === "string" && /^https?:\/\//.test(value)) return value;
307	  }
308	  if (!market.externalId) return null;
309	  if (String(market.source) === "POLYMARKET") {
310	    return `https://polymarket.com/event/${market.externalId}`;
311	  }
312	  if (String(market.source) === "KALSHI") {
313	    return `https://kalshi.com/markets/${market.externalId}`;
314	  }
315	  return null;
316	}
317	
318	function currentSidePrice(
319	  market: { currentYesPrice: unknown; currentNoPrice: unknown } | null,
320	  side: ForecastBetSide | string,
321	): number | null {
322	  if (!market) return null;
323	  return String(side) === "NO"
324	    ? decimalNumber(market.currentNoPrice)
325	    : decimalNumber(market.currentYesPrice);
326	}
327	
328	function paperUnrealizedPnl(bet: {
329	  entryPrice: unknown;
330	  mode: string;
331	  side: ForecastBetSide | string;
332	  stakeUsd: unknown;
333	  status: string;
334	  prediction: { market: { currentYesPrice: unknown; currentNoPrice: unknown } | null } | null;
335	}): number {
336	  if (bet.mode !== "PAPER" || bet.status !== "FILLED") return 0;
337	  const entry = decimalNumber(bet.entryPrice);
338	  const current = currentSidePrice(bet.prediction?.market ?? null, bet.side);
339	  const stake = money(bet.stakeUsd);
340	  if (!entry || !current || stake <= 0) return 0;
341	  const shares = stake / entry;
342	  return shares * current - stake;
343	}
344	
345	function gateState(gates: TraceGateResult[]): string {
346	  const failed = gates.find((gate) => !gate.passed);
347	  if (failed) return `would fail ${failed.gateName}: ${failed.reason}`;
348	  return "paper-ready";
349	}
350	
351	export async function getForecastPortfolioSurface(
352	  organizationId: string,
353	): Promise<ForecastPortfolioSurface> {
354	  const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
355	
356	  const [
357	    portfolioState,
358	    openBets,
359	    settledPaperBets,
360	    resolvedRows,
361	    openMarkets,
362	    scannedThisWeek,
363	    watchedMarkets,
364	  ] = await Promise.all([
365	    db.forecastPortfolioState.findUnique({ where: { organizationId } }),
366	    db.forecastBet.findMany({
367	      where: {
368	        organizationId,
369	        status: { in: ["PENDING", "AUTHORIZED", "CONFIRMED", "SUBMITTED", "FILLED"] },
370	      },
371	      include: {
372	        prediction: {
373	          include: {
374	            market: true,
375	            trace: true,
376	          },
377	        },
378	      },
379	      orderBy: { createdAt: "desc" },
380	      take: 100,
381	    }),
382	    db.forecastBet.findMany({
383	      where: {
384	        organizationId,
385	        mode: "PAPER",
386	        status: "SETTLED",
387	      },
388	      orderBy: { settledAt: "desc" },
389	      take: 200,
390	    }),
391	    db.forecastBet.findMany({
392	      where: {
393	        organizationId,
394	        status: "SETTLED",
395	      },
396	      include: {
397	        prediction: {
398	          include: {
399	            market: true,
400	            resolution: true,
401	          },
402	        },
403	      },
404	      orderBy: { settledAt: "desc" },
405	      take: 25,
406	    }),
407	    db.forecastMarket.findMany({
408	      where: {
409	        organizationId,
410	        status: "OPEN",
411	      },
412	      include: {
413	        predictions: {
414	          include: { trace: true },
415	          orderBy: { createdAt: "desc" },
416	          take: 1,
417	        },
418	      },
419	      orderBy: { updatedAt: "desc" },
420	      take: 30,
421	    }),
422	    db.forecastMarket.count({
423	      where: {
424	        organizationId,
425	        updatedAt: { gte: weekAgo },
426	      },
427	    }),
428	    db.watchedMarket.findMany({
429	      where: { organizationId },
430	      orderBy: { createdAt: "desc" },
431	      take: 50,
432	    }),
433	  ]);
434	
435	  const realizedPaperPnl = settledPaperBets.reduce(
436	    (sum, bet) => sum + money(bet.settlementPnlUsd),
437	    0,
438	  );
439	  const wins = settledPaperBets.filter((bet) => money(bet.settlementPnlUsd) > 0).length;
440	  const brierScores = resolvedRows
441	    .map((bet) => bet.prediction?.resolution?.brierScore)
442	    .map(decimalNumber)
443	    .filter((value): value is number => value !== null);
444	
445	  return {
446	    mode: modeState({
447	      killSwitchEngaged: Boolean(portfolioState?.killSwitchEngaged),
448	      killSwitchReason: portfolioState?.killSwitchReason ?? null,
449	    }),
450	    kpis: {
451	      hitRate: settledPaperBets.length > 0 ? wins / settledPaperBets.length : null,
452	      openPositions: openBets.length,
453	      realizedPaperPnl,
454	      runningBrier:
455	        brierScores.length > 0
456	          ? brierScores.reduce((sum, value) => sum + value, 0) / brierScores.length
457	          : portfolioState?.meanBrier90d ?? null,
458	      unrealizedPaperPnl: openBets.reduce((sum, bet) => sum + paperUnrealizedPnl(bet), 0),
459	    },
460	    openPositions: openBets.map((bet) => {
461	      const prediction = bet.prediction;
462	      const market = prediction?.market ?? null;
463	      const trace = prediction?.trace ?? null;
464	      const decisionTrace = trace
465	        ? normalizeDecisionTrace(trace.modelOutput, {
466	            firmProbabilityYes: decimalNumber(prediction?.probabilityYes),
467	            marketYesPrice: decimalNumber(market?.currentYesPrice),
468	          })
469	        : null;
470	      return {
471	        avgPrice: money(bet.entryPrice),
472	        betId: bet.id,
473	        currentImpliedProb: currentSidePrice(market, bet.side),
474	        decisionTrace,
475	        drivingPrinciples: normalizeTracePrinciples(trace?.principlesUsed),
476	        gateResults: normalizeGateResults(trace?.gateResults),
477	        lastUpdated: prediction?.updatedAt ?? bet.createdAt,
478	        marketTitle: market?.title ?? trace?.marketTitle ?? prediction?.headline ?? "Unknown market",
479	        marketUrl: market ? marketUrl(market) : null,
480	        mode: bet.mode,
481	        predictionId: bet.predictionId,
482	        side: bet.side,
483	        sizeUsd: money(bet.stakeUsd),
484	      };
485	    }),
486	    pipeline: openMarkets.map((market) => {
487	      const prediction = market.predictions[0] ?? null;
488	      const trace = prediction?.trace ?? null;
489	      const gates = normalizeGateResults(trace?.gateResults);
490	      const gateResults =
491	        gates.length > 0
492	          ? gates
493	          : [
494	              {
495	                gateName: "retrieval_queue",
496	                passed: true,
497	                reason: "awaiting the next forecast generator cycle",
498	              },
499	            ];
500	      const decisionTrace = trace
501	        ? normalizeDecisionTrace(trace.modelOutput, {
502	            firmProbabilityYes: decimalNumber(prediction?.probabilityYes),
503	            marketYesPrice: decimalNumber(market.currentYesPrice),
504	          })
505	        : null;
506	      return {
507	        category: market.category,
508	        decisionTrace,
509	        drivingPrinciples: normalizeTracePrinciples(trace?.principlesUsed),
510	        gateResults,
511	        gateState: gateState(gateResults),
512	        lastUpdated: market.updatedAt,
513	        marketId: market.id,
514	        marketNoPrice: decimalNumber(market.currentNoPrice),
515	        marketTitle: market.title,
516	        marketUrl: marketUrl(market),
517	        marketYesPrice: decimalNumber(market.currentYesPrice),
518	        predictionId: prediction?.id ?? null,
519	        source: market.source,
520	      };
521	    }),
522	    recentlyResolved: resolvedRows.map((bet) => {
523	      const prediction = bet.prediction;
524	      const market = prediction?.market ?? null;
525	      return {
526	        betId: bet.id,
527	        marketTitle: market?.title ?? prediction?.headline ?? "Unknown market",
528	        marketUrl: market ? marketUrl(market) : null,
529	        outcome: prediction?.resolution?.marketOutcome ?? "UNKNOWN",
530	        ourSide: bet.side,
531	        pnlUsd: decimalNumber(bet.settlementPnlUsd),
532	        predictionId: bet.predictionId,
533	        reasoningHref: `/forecasts/${bet.predictionId}`,
534	        resolvedAt: prediction?.resolution?.resolvedAt ?? bet.settledAt,
535	      };
536	    }),
537	    watching: {
538	      kalshiCategories: csvEnv("FORECASTS_KALSHI_CATEGORIES"),
539	      polymarketCategories: csvEnv("FORECASTS_POLYMARKET_CATEGORIES"),
540	      scannedThisWeek,
541	      watchedMarkets: watchedMarkets.map((row) => ({
542	        createdAt: row.createdAt,
543	        externalId: row.externalId,
544	        id: row.id,
545	        lastConsideredAt: row.lastConsideredAt,
546	        source: row.source,
547	        status: row.status,
548	        url: row.url,
549	      })),
550	    },
551	  };
552	}
553

