import type { CSSProperties } from "react";

import {
  DECISION_ACTION_BLURBS,
  METRIC_DEFINITIONS,
  type DecisionAction,
  type DecisionMetric,
  type DecisionRule,
  type DecisionTrace,
} from "@/lib/forecastsTypes";

const wrapStyle: CSSProperties = {
  border: "1px solid rgba(232, 225, 211, 0.12)",
  borderRadius: 6,
  display: "grid",
  gap: "0.7rem",
  padding: "0.85rem",
};

const gridStyle: CSSProperties = {
  display: "grid",
  gap: "0.55rem",
  gridTemplateColumns: "repeat(auto-fit, minmax(170px, 1fr))",
};

const cellStyle: CSSProperties = {
  background: "rgba(232, 225, 211, 0.03)",
  border: "1px solid rgba(232, 225, 211, 0.08)",
  borderRadius: 4,
  padding: "0.45rem 0.55rem",
};

const labelStyle: CSSProperties = {
  color: "var(--amber-dim)",
  fontSize: "0.58rem",
  letterSpacing: "0.18em",
  textTransform: "uppercase",
};

const valueStyle: CSSProperties = {
  color: "var(--parchment)",
  display: "block",
  fontSize: "0.96rem",
  marginTop: "0.15rem",
};

function actionColor(action: DecisionAction): string {
  switch (action) {
    case "LIVE_CANDIDATE":
      return "var(--amber)";
    case "PAPER_TRADE":
      return "rgba(127, 196, 143, 0.95)";
    case "WATCH":
      return "rgba(212, 178, 90, 0.95)";
    case "REDUCE":
    case "EXIT":
      return "var(--ember)";
    case "HEDGE":
      return "rgba(170, 159, 220, 0.95)";
    default:
      return "var(--parchment-dim)";
  }
}

function fmtPct(value: number | null | undefined): string {
  if (value === null || value === undefined || !Number.isFinite(value)) return "n/a";
  return `${(value * 100).toFixed(1)}%`;
}

function fmtSignedPct(value: number | null | undefined): string {
  if (value === null || value === undefined || !Number.isFinite(value)) return "n/a";
  const sign = value >= 0 ? "+" : "";
  return `${sign}${(value * 100).toFixed(1)} pp`;
}

function fmtScalar(value: number): string {
  if (!Number.isFinite(value)) return "n/a";
  return value.toFixed(3);
}

function fmtUsd(value: number | null): string {
  if (value === null || !Number.isFinite(value)) return "—";
  return new Intl.NumberFormat("en-US", {
    currency: "USD",
    maximumFractionDigits: 2,
    style: "currency",
  }).format(value);
}

export function ActionBadge({
  action,
  size = "md",
}: {
  action: DecisionAction;
  size?: "sm" | "md";
}) {
  const accent = actionColor(action);
  return (
    <span
      className="mono"
      data-decision-action={action}
      style={{
        border: `1px solid ${accent}`,
        borderRadius: 999,
        color: accent,
        fontSize: size === "sm" ? "0.58rem" : "0.68rem",
        letterSpacing: "0.12em",
        padding: size === "sm" ? "0.12rem 0.42rem" : "0.22rem 0.55rem",
      }}
    >
