  padding: "0.85rem",
};

const gridStyle: CSSProperties = {
  display: "grid",
  gap: "0.55rem",
  gridTemplateColumns: "repeat(auto-fit, minmax(170px, 1fr))",
};

const cellStyle: CSSProperties = {
  background: "rgba(232, 225, 211, 0.03)",
