              <span
                style={{
                  marginLeft: "0.35rem",
                  color: "var(--parchment-dim)",
                  fontSize: "0.65rem",
                }}
              >
                {s.sourceType}
              </span>
            </Link>
          ))}
        </div>
      ) : null}
    </header>
  );
}

