            </time>
          </SummaryPair>
        ) : null}
      </dl>

      {rationale ? (
        <p
          style={{
            margin: "0.65rem 0 0",
            fontSize: "0.9rem",
            color: "var(--parchment)",
            lineHeight: 1.55,
