          style={{
            margin: "0.55rem 0 0",
            display: "flex",
            flexWrap: "wrap",
            gap: "0.4rem",
            alignItems: "center",
          }}
        >
          <span
            className="mono"
            style={{
              color: "var(--parchment-dim)",
              fontSize: "0.6rem",
              letterSpacing: "0.18em",
              textTransform: "uppercase",
            }}
          >
            Abstracted into
