              {p.text.slice(0, 90)}
              {p.text.length > 90 ? "…" : ""}
            </Link>
          ))}
        </div>
      ) : null}

      {sources.length > 0 ? (
        <div
          style={{
            margin: "0.65rem 0 0",
            display: "flex",
            flexWrap: "wrap",
            gap: "0.4rem",
