              fontSize: "0.6rem",
              letterSpacing: "0.18em",
              textTransform: "uppercase",
            }}
          >
            Source
          </span>
          {sources.map((s) => (
            <Link
              key={s.uploadId}
              href="/knowledge?tab=library"
