const CLAIM_KIND_LABELS: Record<
  "abstract_principle" | "empirical" | "decision_rule" | "unclassified",
  { label: string; tooltip: string; color: string }
> = {
  abstract_principle: {
    color: "var(--gold)",
    label: "Abstract principle",
    tooltip:
      "This conclusion is referenced by an accepted Principle row, so the firm treats it as a load-bearing abstract rule.",
  },
  decision_rule: {
    color: "var(--amber)",
    label: "Decision rule",
    tooltip:
      "Reads as an action policy (a should/must rule) rather than a description of the world.",
  },
  empirical: {
    color: "var(--amber)",
    label: "Empirical observation",
    tooltip:
      "Firm/founder-tier claim grounded in source material; no abstract-principle link recorded yet.",
  },
  unclassified: {
    color: "var(--parchment-dim)",
    label: "Unclassified",
    tooltip:
      "Open or speculative; the firm has not assigned this conclusion to a principle or treated it as an empirical baseline.",
  },
};

function ClaimSummary({
  claim,
  tier,
  tierColor,
  confidence,
  topicHint,
  attribution,
  rationale,
  createdAt,
  updatedAt,
  sources,
  claimKind,
  linkedPrinciples,
}: {
  claim: string;
  tier: string;
  tierColor: string;
  confidence: number;
  topicHint: string;
  attribution: string;
  rationale: string;
  createdAt: string;
  updatedAt: string;
  sources: { uploadId: string; title: string; sourceType: string }[];
  claimKind: "abstract_principle" | "empirical" | "decision_rule" | "unclassified";
  linkedPrinciples: { id: string; text: string }[];
}) {
  const kind = CLAIM_KIND_LABELS[claimKind];
  const pct = Math.max(0, Math.min(1, confidence)) * 100;
  const showUpdated = updatedAt && updatedAt !== createdAt;
  return (
    <header style={{ marginBottom: "1rem" }}>
      <blockquote
        style={{
          margin: 0,
          padding: "0.85rem 1.15rem",
          borderLeft: `3px solid ${tierColor}`,
          background: "var(--stone-light)",
          fontSize: "1.1rem",
          lineHeight: 1.55,
          color: "var(--parchment)",
        }}
      >
        {claim}
      </blockquote>

      <dl
        style={{
          display: "flex",
          flexWrap: "wrap",
          gap: "0.4rem 1rem",
          margin: "0.75rem 0 0",
          padding: 0,
          fontSize: "0.75rem",
          color: "var(--parchment-dim)",
          alignItems: "baseline",
        }}
      >
        <SummaryPair label="Tier">
          <span
            style={{
              color: tierColor,
              textTransform: "uppercase",
              letterSpacing: "0.1em",
              fontFamily: "'Cinzel', serif",
              fontSize: "0.7rem",
            }}
          >
            {tier}
          </span>
        </SummaryPair>
        <SummaryPair label="Kind">
          <span
            data-claim-kind={claimKind}
            title={kind.tooltip}
            style={{
              color: kind.color,
              fontFamily: "'Cinzel', serif",
              fontSize: "0.7rem",
              letterSpacing: "0.1em",
              textTransform: "uppercase",
            }}
          >
            {kind.label}
          </span>
        </SummaryPair>
        <SummaryPair label="Confidence">
          <span style={{ color: "var(--parchment)" }}>{pct.toFixed(0)}%</span>
        </SummaryPair>
        {topicHint ? (
          <SummaryPair label="Topic">
            <span style={{ color: "var(--parchment)" }}>{topicHint}</span>
          </SummaryPair>
        ) : null}
        {attribution ? (
          <SummaryPair label="Attributed to">
            <span style={{ color: "var(--parchment)" }}>{attribution}</span>
          </SummaryPair>
        ) : null}
        {createdAt ? (
          <SummaryPair label={showUpdated ? "Created" : "Recorded"}>
            <time dateTime={createdAt} style={{ color: "var(--parchment)" }}>
              {createdAt}
            </time>
          </SummaryPair>
        ) : null}
        {showUpdated ? (
          <SummaryPair label="Updated">
            <time dateTime={updatedAt} style={{ color: "var(--parchment)" }}>
              {updatedAt}
            </time>
          </SummaryPair>
        ) : null}
      </dl>

      {rationale ? (
        <p
          style={{
            margin: "0.65rem 0 0",
            fontSize: "0.9rem",
            color: "var(--parchment)",
            lineHeight: 1.55,
          }}
        >
          <span
            className="mono"
            style={{
              color: "var(--parchment-dim)",
              fontSize: "0.6rem",
              letterSpacing: "0.18em",
              textTransform: "uppercase",
              marginRight: "0.45rem",
            }}
          >
            Rationale
          </span>
          {rationale}
        </p>
      ) : null}

      {linkedPrinciples.length > 0 ? (
        <div
          style={{
            margin: "0.55rem 0 0",
            display: "flex",
            flexWrap: "wrap",
            gap: "0.4rem",
            alignItems: "center",
          }}
        >
          <span
            className="mono"
            style={{
              color: "var(--parchment-dim)",
              fontSize: "0.6rem",
              letterSpacing: "0.18em",
              textTransform: "uppercase",
            }}
          >
            Abstracted into
          </span>
          {linkedPrinciples.map((p) => (
            <Link
              key={p.id}
              href={`/principles/${p.id}`}
              title={p.text}
              style={{
                border: "1px solid rgba(205, 151, 67, 0.55)",
                borderRadius: 2,
                color: "var(--amber)",
                fontSize: "0.74rem",
                padding: "0.15rem 0.5rem",
                textDecoration: "none",
              }}
            >
              {p.text.slice(0, 90)}
              {p.text.length > 90 ? "…" : ""}
            </Link>
          ))}
        </div>
      ) : null}

      {sources.length > 0 ? (
        <div
          style={{
            margin: "0.65rem 0 0",
            display: "flex",
            flexWrap: "wrap",
            gap: "0.4rem",
            alignItems: "center",
          }}
        >
          <span
            className="mono"
            style={{
              color: "var(--parchment-dim)",
              fontSize: "0.6rem",
              letterSpacing: "0.18em",
              textTransform: "uppercase",
            }}
