                      style={{
                        color: "var(--amber-dim)",
                        fontSize: "0.58rem",
                        letterSpacing: "0.18em",
                        textTransform: "uppercase",
                      }}
                    >
                      Why:
                    </span>{" "}
                    {trace.reasons[0]}
