                <div style={{ display: "flex", flexWrap: "wrap", gap: "0.4rem", marginTop: "0.7rem" }}>
                  {(["DISABLED", "NOT_CONFIGURED", "STAKE_OVER_CEILING", "DAILY_LOSS_OVER_CEILING", "KILL_SWITCH_ENGAGED", "INSUFFICIENT_BALANCE"] as ConfirmGateCode[]).map((code) => (
