                      className="mono"
                      data-gate-code={code}
                      data-gate-state={failures.includes(code) ? "fail" : "pass"}
                      key={code}
                      style={{
                        border: `1px solid ${failures.includes(code) ? "rgba(185, 92, 92, 0.65)" : "rgba(126, 166, 133, 0.55)"}`,
